# Prompt: Build a function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os

def delete_uploaded_file(filename):
    path = f"uploads/{filename}"
    
    if os.path.exists(path):
        try:
            os.remove(path)
            return True
        except Exception as e:
            print(f"Error deleting file: {e}")
            return False
    else:
        return False

# Example usage
print(delete_uploaded_file('example.txt'))